card_mod.style:
{% set lvl = states('sensor.jon_phone_battery_level') | int %}
{% set chg = states('sensor.jon_phone_battery_state') %}
{% set home = states('person.jon') == 'home' %}

ha-card {
  border-radius: 18px;
  transition: 0.4s ease;
  background-color: rgba(255,255,0,0.15);
  box-shadow: 0 0 18px rgba(255,255,0,0.25);
}

/* FORCE ALL TEXT TO BLACK */
ha-card,
ha-card * {
  color: black !important;
}

/* Pulse only when home */
{% if home and (chg == 'charging' or lvl < 20) %}
ha-card { animation: pulse 1.5s ease-out 1; }
{% endif %}

@keyframes pulse {
  0% { transform: scale(1); opacity: 1; }
  50% { transform: scale(1.15); opacity: 0.6; }
  100% { transform: scale(1); opacity: 1; }
}

/* Charging background fill only when home */
{% if home and chg == 'charging' %}
ha-card {
  background-image: linear-gradient(
    to top,
    rgba(255,255,0,0.35) 0%,
    rgba(255,255,0,0.15) 40%,
    rgba(255,255,0,0.05) 70%,
    rgba(255,255,0,0.00) 100%
  );
  background-size: 100% 300%;
  animation: batteryFill 2.5s linear infinite;
}
{% endif %}

@keyframes batteryFill {
  0%   { background-position: 0% 100%; }
  100% { background-position: 0% 0%; }
}

/* Battery bar background */
ha-card::after {
  content: "";
  display: block;
  height: 10px;
  width: 100%;
  margin-top: 8px;
  border-radius: 4px;
  background: rgba(255,255,255,0.15);
  position: relative;
  overflow: hidden;
}

/* Battery bar fill (dynamic width + transparent gradient) */
ha-card::before {
  content: "{{ lvl }}%";
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 8px;
  font-weight: bold;
  color: black;
  height: 100%;
  width: {{ lvl }}%;
  border-radius: 4px;
  position: absolute;
  top: 0;
  left: 0;
  background: linear-gradient(
    90deg,
    rgba(255,255,0,0.55) 0%,
    rgba(204,204,0,0.55) 100%
  );
  transition: width 0.4s ease;
  text-shadow: 0 0 3px rgba(255,255,255,0.8);
}

/* Charging glow only when home */
{% if home and chg == 'charging' %}
ha-card::before {
  box-shadow: 0 0 8px rgba(255,255,0,0.7);
  animation: batteryFlow 1.8s linear infinite;
  background-size: 200% 100%;
}
{% endif %}

@keyframes batteryFlow {
  0%   { background-position: 200% 0; }
  100% { background-position: -200% 0; }
}

/* Shake when low battery */
{% if lvl < 15 %}
ha-card::before { animation: shake 0.4s ease-in-out infinite; }
{% endif %}

@keyframes shake {
  0% { transform: translateX(0); }
  25% { transform: translateX(-2px); }
  50% { transform: translateX(2px); }
  75% { transform: translateX(-2px); }
  100% { transform: translateX(0); }
}

