card.background:
[[[
  const hour = new Date().getHours();
  if (hour < 7) return "linear-gradient(135deg, #1a1a2e, #16213e)";
  if (hour < 18) return "linear-gradient(135deg, #4facfe, #00f2fe)";
  return "linear-gradient(135deg, #654ea3, #eaafc8)";
]]]

custom_fields.time:
[[[
  const d = new Date();
  const h = d.getHours().toString().padStart(2,'0');
  const m = d.getMinutes().toString().padStart(2,'0');
  return `<div style="font-size:2.2rem;font-weight:600;">${h}:${m}</div>`;
]]]

custom_fields.weather:
[[[
  const temp = states['weather.home_weather']?.attributes?.temperature ?? '--';
  const cond = states['weather.home_weather']?.state ?? '';
  const icon = {
    'sunny': 'mdi:weather-sunny',
    'clear-night': 'mdi:weather-night',
    'cloudy': 'mdi:weather-cloudy',
    'partlycloudy': 'mdi:weather-partly-cloudy',
    'rainy': 'mdi:weather-rainy',
    'snowy': 'mdi:weather-snowy',
    'fog': 'mdi:weather-fog'
  }[cond] || 'mdi:weather-cloudy';

  return `
    <ha-icon icon="${icon}" style="width:32px;height:32px;color:white;"></ha-icon>
    <div style="font-size:1.4rem;margin-top:6px;">${temp}°C</div>
    <div style="font-size:0.9rem;opacity:0.8;">${cond.replace('-', ' ')}</div>
  `;
]]]

custom_fields.presence:
[[[
  const rooms = [
    'sensor.jon_room',
    'sensor.natalie_room',
    'sensor.jacob_room'
  ];

  const present = rooms
    .map(r => states[r])
    .filter(v => v && v !== 'not_home');

  let text = "";
  if (present.length === 0) text = "Nobody home";
  else if (present.length === 1) text = `${present[0]} active`;
  else text = present.join(', ') + " active";

  return `
    <div style="font-size:1.2rem;font-weight:500;">${text}</div>
  `;
]]]
